import{_ as e,o as a,c as r,a7 as d}from"./chunks/framework.C5fSpjcB.js";const h=JSON.parse('{"title":"Key Orders List","description":"","frontmatter":{},"headers":[],"relativePath":"en/key-orders/list.md","filePath":"en/key-orders/list.md","lastUpdated":1775394001000}'),n={name:"en/key-orders/list.md"};function s(o,t,i,l,c,u){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="key-orders-list" tabindex="-1">Key Orders List <a class="header-anchor" href="#key-orders-list" aria-label="Permalink to &quot;Key Orders List&quot;">​</a></h1><p>A complete list of all 20 Key Orders in Morimens. Key Orders are the Keeper&#39;s exclusive combat abilities, activated by spending 1000 Silver Key Energy. Introduced in v2.0.</p><h2 id="all-key-orders" tabindex="-1">All Key Orders <a class="header-anchor" href="#all-key-orders" aria-label="Permalink to &quot;All Key Orders&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key Order</th><th>Realm Affinity</th><th>Category</th><th>Effect</th><th>Source</th></tr></thead><tbody><tr><td>Mouse Wisdom</td><td>Universal</td><td>Resource</td><td>Gain 3 Arithmetica.</td><td>Clear Main Story 2-15</td></tr><tr><td>Little Wish</td><td>Universal</td><td>Fury</td><td>Select 1 Awakener, grant them 35 Aliemus.</td><td>Main Story</td></tr><tr><td>The Tavern Door</td><td>Universal</td><td>Draw</td><td>Place 1 &quot;Lia&#39;s Coin&quot; (gain 2 AP and draw 2 cards) into discard pile.</td><td>Clear Multidimensional &quot;Reversal...&quot;</td></tr><tr><td>Injection Guard</td><td>Universal</td><td>Defense</td><td>Defense/shield related effect (unconfirmed).</td><td>Main Story</td></tr><tr><td>Eternal Obsession</td><td>Universal</td><td>Power Burst</td><td>Gain 25% temporary crit rate and 7 temporary Power. In Boss fights, if no cards played this turn, trigger 1 Death Resist; on success gain 138 shield (1x only).</td><td>Main Story</td></tr><tr><td>Unequal Exchange</td><td>Universal</td><td>Utility</td><td>Positive effect (unconfirmed). v1.1: removed &quot;draw 1 fewer card next turn&quot; side effect.</td><td>Main Story</td></tr><tr><td>A Momentary Dream</td><td>Universal</td><td>Draw/Utility</td><td>Draw 1 card; if it is a command card or Gnosis Awakening, set its AP cost to 0; otherwise discard and repeat. Permanently increase Realm Mastery by 25.</td><td>Main Story</td></tr><tr><td>The Final Oath</td><td>Universal</td><td>Power Burst</td><td>Gain 23 temporary Power and 25% temporary crit rate. In Boss fights, if no cards played this turn, trigger 1 Death Resist; on success gain 1 Barrier (1x only). Values at Keeper Lv60.</td><td>Expansion/Story</td></tr><tr><td>Roar of Blood and Sand</td><td><span class="realm-badge realm-caro">Caro</span></td><td>Fury/Power</td><td>Lose 10% current HP, select 1 Awakener to gain 25 Aliemus and gain 12 Power. Caro bonus: Embryo Fusion +25.</td><td>Expansion/Story</td></tr><tr><td>Corrosive Embrace</td><td><span class="realm-badge realm-aequor">Aequor</span></td><td>Resource/Defense</td><td>Gain 1 AP; next turn gain 75 shield. Aequor bonus: instead of shield, generate 1 Tentacle.</td><td>Expansion/Story</td></tr><tr><td>Brief Eternity</td><td><span class="realm-badge realm-ultra">Ultra</span></td><td>Card Generation</td><td>Select 1 Awakener, place 2 of their Strike and Defense cards into hand with Exhaust and Void. Ultra bonus: additionally gain 15 temporary Power and 4 temporary Guard.</td><td>Expansion/Story</td></tr><tr><td>Ashen Mist Visage</td><td><span class="realm-badge realm-ultra">Ultra</span></td><td>Crit/Draw</td><td>Permanently increase crit rate by 5%; place 1 &quot;Inspiration&quot; into hand. Ultra bonus (during Ultra turn): place 1 additional Inspiration into hand.</td><td>Expansion/Story</td></tr><tr><td>Lakeside Glance</td><td><span class="realm-badge realm-caro">Caro</span></td><td>Defense/Poison</td><td>Gain 60 shield; inflict Poison equal to 25% of team&#39;s shield on all enemies. Caro bonus: the more HP lost, the higher poison, up to 50% of shield value.</td><td>Expansion/Story</td></tr><tr><td>Retrospective End</td><td>Universal</td><td>Card Replay</td><td>Place an original copy of the last non-derived command card played last turn into hand, with AP cost -1, Exhaust and Void.</td><td>Expansion/Story</td></tr><tr><td>Victory of the Rose</td><td><span class="realm-badge realm-caro">Caro</span></td><td>Healing/Power</td><td>Restore 45 HP. Below 25% HP, gain temporary Power equal to heal amount. Caro bonus: +50% heal, no direct heal -- stored in Scarlet Furnace instead.</td><td>Expansion/Story</td></tr><tr><td>Immortal Funeral Rites</td><td>Universal</td><td>Fury/Sacrifice</td><td>All Awakeners gain 12 Aliemus; next turn start, take sacrifice equal to 5% max HP.</td><td>Expansion/Story</td></tr><tr><td>Aurita&#39;s Treasure</td><td><span class="realm-badge realm-aequor">Aequor</span></td><td>Draw/Tentacle</td><td>Place the 3 lowest-AP cards from draw pile into hand. Aequor bonus: additionally increase tentacle DMG by 4-8.</td><td>Expansion/Story</td></tr><tr><td>Year-End Fireworks</td><td>Universal</td><td>Potency/Skill</td><td>Select an ally, grant +1 temporary Potency and 2 different skills; discard all hand cards at end of turn.</td><td>v1.1.11 Update</td></tr><tr><td>Manor Memories</td><td>Universal</td><td>Debuff</td><td>Select an ally; inflict 1 stack of &quot;Intoxication&quot; on all other allies and all enemies. (Intoxication: command card/Aliemus burst DMG/heal/shield -10%, cannot be dispelled, max 2 stacks.)</td><td>Story</td></tr><tr><td>Bleeding Sacred Heart</td><td>Universal</td><td>Draw/Crit</td><td>Draw 1 highest-AP &quot;Skill&quot; card, grant it Readied. Pollux special: gain 5 stacks of &quot;Sin Mark&quot;.</td><td>Story/Event</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Key Orders pair especially well with <span class="realm-badge realm-chaos">Chaos</span> teams due to their accelerated Silver Key generation. Pure Chaos teams auto-generate 250 Silver Key Energy per turn and can use Key Orders twice per turn. Prioritize upgrading your Key Order if you run a Chaos-focused team.</p></div><h2 id="team-recommendations" tabindex="-1">Team Recommendations <a class="header-anchor" href="#team-recommendations" aria-label="Permalink to &quot;Team Recommendations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Team Type</th><th>Recommended Key Orders</th><th>Reason</th></tr></thead><tbody><tr><td>Deep Sea Tentacle</td><td>Aurita&#39;s Treasure, Corrosive Embrace</td><td>Tentacle generation and tentacle DMG bonus</td></tr><tr><td>Caro Embryo/Fusion</td><td>Roar of Blood and Sand, Lakeside Glance, Victory of the Rose</td><td>Embryo Fusion boost, HP loss synergy, Scarlet Furnace storage</td></tr><tr><td>Ultra Card Chain</td><td>Brief Eternity, Ashen Mist Visage</td><td>Extra hand cards, Inspiration assists Ultra turns</td></tr><tr><td>Power Burst</td><td>Eternal Obsession, The Final Oath</td><td>Large Power and crit rate boosts</td></tr><tr><td>Aliemus Rush</td><td>Immortal Funeral Rites, Roar of Blood and Sand, Little Wish</td><td>Quick Aliemus fill for burst</td></tr><tr><td>Universal / Beginner</td><td>A Momentary Dream, Mouse Wisdom, The Tavern Door</td><td>AP supplement and card draw, works with any team</td></tr></tbody></table><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Key Orders Overview</a></li><li><a href="./../modes/combat.html">Combat System</a></li><li><a href="./../realms/chaos.html">Chaos Realm</a></li></ul>',9)])])}const y=e(n,[["render",s]]);export{h as __pageData,y as default};
